export enum IPTFocus {
  DISPUTES = 'interpersonal_disputes',
  TRANSITION = 'role_transition',
  GRIEF = 'grief',
  DEFICITS = 'interpersonal_deficits',
  UNCERTAIN = 'uncertain'
}

export enum RiskLevel {
  L0 = 0,
  L1 = 1,
  L2 = 2,
  L3 = 3
}

export interface Message {
  id: string;
  role: 'ai' | 'user';
  content: string;
  timestamp: number;
  chips?: string[];
}

export interface Session {
  id: string;
  createdAt: number;
  updatedAt: number;
  iptFocus: IPTFocus;
  riskLevel: RiskLevel;
  step: number; // 1-8
  goal?: string;
  relationshipTarget?: string;
  messages: Message[];
  extracted: {
    eventSummary?: string;
    emotions: string[];
    needs: string[];
    pattern?: string;
  };
  coachScripts?: {
    gentle: string;
    firm: string;
    short: string;
  };
  actionPlan?: {
    task: string;
    successCriteria: string;
    backupPlan: string;
    completed: boolean;
  };
  reflection?: string;
}

export type AppView = 'home' | 'session' | 'coach' | 'action' | 'history';

import { Session } from '../types';

const STORAGE_KEY = 'ipt_sessions_v1';

export const storage = {
  saveSessions: (sessions: Session[]) => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(sessions));
  },
  getSessions: (): Session[] => {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  },
  saveCurrentSession: (session: Session) => {
    const sessions = storage.getSessions();
    const index = sessions.findIndex(s => s.id === session.id);
    if (index >= 0) {
      sessions[index] = session;
    } else {
      sessions.push(session);
    }
    storage.saveSessions(sessions);
  },
  clearAll: () => {
    localStorage.removeItem(STORAGE_KEY);
  }
};

import { RiskLevel } from '../types';

const L3_KEYWORDS = ['自杀', '死', '结束生命', '杀了', '不想活', '安眠药', '遗嘱', '跳楼', '割腕'];
const L2_KEYWORDS = ['没希望', '绝望', '崩溃', '想打人', '失控', '想消失', '没有意义'];

export function identifyRisk(text: string): RiskLevel {
  const lowerText = text.toLowerCase();

  if (L3_KEYWORDS.some(k => lowerText.includes(k))) {
    return RiskLevel.L3;
  }

  if (L2_KEYWORDS.some(k => lowerText.includes(k))) {
    return RiskLevel.L2;
  }

  if (lowerText.length > 50 || lowerText.includes('难受') || lowerText.includes('痛苦')) {
    return RiskLevel.L1;
  }

  return RiskLevel.L0;
}

import { IPTFocus, Session, Message } from '../types';

const STEP_DATA = [
  { step: 1, name: '目标定义', goal: '明确我们今天要解决的核心关系问题。' },
  { step: 2, name: '事件澄清', goal: '还原最近一次让您感到不适的互动细节。' },
  { step: 3, name: '情绪定位', goal: '识别在那一刻，您最真实的情绪反应。' },
  { step: 4, name: '需求澄清', goal: '挖掘情绪背后的心理需求是什么。' },
  { step: 5, name: '角色与期待', goal: '分析您与对方在这个关系中的角色期待。' },
  { step: 6, name: '循环识别', goal: '观察这种互动是否在重复某种模式。' },
  { step: 7, name: '沟通彩排', goal: '尝试用新的表达方式来改写局面。' },
  { step: 8, name: '行动计划', goal: '确定未来24小时内的一个微小行动。' },
];

export const iptEngine = {
  getStepInfo: (step: number) => STEP_DATA[step - 1],

  generateResponse: (session: Session, userInput: string): { response: string; chips?: string[]; updates?: Partial<Session> } => {
    const { step, iptFocus } = session;
    let response = "";
    let chips: string[] = [];
    let updates: Partial<Session> = {};

    switch (step) {
      case 1:
        response = `了解。针对${getFocusName(iptFocus)}，您希望通过这次谈话达到什么目标？例如：缓和关系、表达立场或做出决定。`;
        chips = ["缓和紧张气氛", "明确表达我的需求", "决定是否离开", "减少争吵"];
        break;
      case 2:
        response = "为了更好地理解，请描述最近发生的一个具体片段：当时谁说了什么？您是怎么回应的？";
        chips = ["就在昨天发生的事", "我们为了琐事争吵", "对方一直冷战", "我想不起来具体细节"];
        break;
      case 3:
        response = "在那段互动中，您观察到自己有哪些情绪？（如：委屈、愤怒、无力、恐惧等）";
        chips = ["感到很委屈", "莫名的愤怒", "一种深深的挫败感", "我不确定自己的感受"];
        break;
      case 4:
        response = "这些情绪在告诉我们，您当时最核心的心理需求是什么？是需要被肯定、被尊重，还是需要安全感？";
        chips = ["我需要被尊重", "我需要对方的理解", "我需要一些独立空间", "我需要明确的承诺"];
        break;
      case 5:
        response = "在您看来，您希望对方扮演什么角色？而对方实际上表现出了什么角色？这种期待的落差在哪里？";
        chips = ["希望对方是支持者", "对方像个评判者", "希望平等沟通", "角色完全错位了"];
        break;
      case 6:
        response = "这种互动模式在以前发生过吗？是不是一旦对方XX，您就会XX，最后导致XX？";
        chips = ["经常发生", "每次都是这个结局", "这是我们的老剧本了", "这是第一次发现"];
        break;
      case 7:
        response = "如果我们要打破这个循环，尝试一种新的说法。您想试试看吗？我可以为您生成几个版本的话术。";
        chips = ["请给我建议", "我想试试温和的表达", "我需要表现得更坚定", "跳过，直接定计划"];
        break;
      case 8:
        response = "最后，我们来定一个“最小行动”。在未来24小时内，您可以做的一件不费力的小事是什么？";
        chips = ["给对方发个简短微信", "今晚先保持沉默观察", "主动发起一次谈话", "记录下自己的情绪"];
        break;
      default:
        response = "我们的谈话已经完成。您可以查看行动计划和话术教练。";
    }

    return { response, chips, updates };
  },

  generateScripts: (session: Session) => {
    const need = session.extracted.needs[0] || "理解";
    const event = "刚才那件事";
    return {
      gentle: `“我想和你聊聊${event}。其实我当时感到挺难受的，因为我挺看重你的${need}。我们能不能试着换种方式？”`,
      firm: `“关于${event}，我希望你能明白，我的${need}对我非常重要。如果能得到你的尊重，我会感觉好很多。”`,
      short: `“关于这件事，我现在的核心需求是${need}，希望你能听听看。”`
    };
  }
};

function getFocusName(focus: IPTFocus): string {
  const map = {
    [IPTFocus.DISPUTES]: '人际冲突',
    [IPTFocus.TRANSITION]: '角色转变',
    [IPTFocus.GRIEF]: '哀伤处理',
    [IPTFocus.DEFICITS]: '社交孤立',
    [IPTFocus.UNCERTAIN]: '关系困扰'
  };
  return map[focus];
}

