const STEP_DATA = [
  { step: 1, name: '目标定义', goal: '明确我们今天要解决的核心关系问题。' },
  { step: 2, name: '事件澄清', goal: '还原最近一次让您感到不适的互动细节。' },
  { step: 3, name: '情绪定位', goal: '识别在那一刻，您最真实的情绪反应。' },
  { step: 4, name: '需求澄清', goal: '挖掘情绪背后的心理需求是什么。' },
  { step: 5, name: '角色与期待', goal: '分析您与对方在这个关系中的角色期待。' },
  { step: 6, name: '循环识别', goal: '观察这种互动是否在重复某种模式。' },
  { step: 7, name: '沟通彩排', goal: '尝试用新的表达方式来改写局面。' },
  { step: 8, name: '行动计划', goal: '确定未来24小时内的一个微小行动。' },
  { step: 9, name: '咨询完成', goal: '您已完成本次结构化咨询，请查看方案。' },
];

export const iptEngine = {
  getStepInfo: (step: number) => STEP_DATA[Math.min(step - 1, 8)],

  generateResponse: (session: Session, userInput: string): { response: string; chips?: string[]; updates?: Partial<Session> } => {
    const { step, iptFocus } = session;
    let response = "";
    let chips: string[] = [];
    let updates: Partial<Session> = {};

    // Basic Extraction Logic
    if (step === 3) {
       updates.extracted = { ...session.extracted, emotions: [userInput] };
    } else if (step === 4) {
       updates.extracted = { ...session.extracted, needs: [userInput] };
    } else if (step === 2) {
       updates.extracted = { ...session.extracted, eventSummary: userInput };
    } else if (step === 8) {
       updates.actionPlan = {
         task: userInput,
         successCriteria: "完成该行动并记录感受",
         backupPlan: "如果没能完成，明天我们再调整方案",
         completed: false
       };
    }

    switch (step) {
      case 1:
        response = `了解。针对${getFocusName(iptFocus)}，您希望通过这次谈话达到什么目标？例如：缓和关系、表达立场或做出决定。`;
        chips = ["缓和紧张气氛", "明确表达我的需求", "决定是否离开", "减少争吵"];
        break;
      case 2:
        response = "为了更好地理解，请描述最近发生的一个具体片段：当时谁说了什么？您是怎么回应的？";
        chips = ["就在昨天发生的事", "我们为了琐事争吵", "对方一直冷战", "我想不起来具体细节"];
        break;
      case 3:
        response = "在那段互动中，您观察到自己有哪些情绪？（如：委屈、愤怒、无力、恐惧等）";
        chips = ["感到很委屈", "莫名的愤怒", "一种深深的挫败感", "我不确定自己的感受"];
        break;
      case 4:
        response = "这些情绪在告诉我们，您当时最核心的心理需求是什么？是需要被肯定、被尊重，还是需要安全感？";
        chips = ["我需要被尊重", "我需要对方的理解", "我需要一些独立空间", "我需要明确的承诺"];
        break;
      case 5:
        response = "在您看来，您希望对方扮演什么角色？而对方实际上表现出了什么角色？这种期待的落差在哪里？";
        chips = ["希望对方是支持者", "对方像个评判者", "希望平等沟通", "角色完全错位了"];
        break;
      case 6:
        response = "这种互动模式在以前发生过吗？是不是一旦对方XX，您就会XX，最后导致XX？";
        chips = ["经常发生", "每次都是这个结局", "这是我们的老剧本了", "这是第一次发现"];
        break;
      case 7:
        response = "如果我们要打破这个循环，尝试一种新的说法。您想试试看吗？我可以为您生成几个版本的话术。";
        chips = ["请给我建议", "我想试试温和的表达", "我需要表现得更坚定", "跳过，直接定计划"];
        break;
      case 8:
        response = "最后，我们来定一个“最小行动”。在未来24小时内，您可以做的一件不费力的小事是什么？";
        chips = ["给对方发个简短微信", "今晚先保持沉默观察", "主动发起一次谈话", "记录下自己的情绪"];
        break;
      case 9:
        response = "太棒了，我们已经梳理完了整个流程。我已经为您生成了专属的话术建议和行动计划。您可以点击下方的“教练”或“计划”查看详情。";
        chips = ["查看话术", "查看计划", "结束咨询"];
        break;
      default:
        response = "我们的谈话已经完成。您可以查看行动计划和话术教练。";
    }

    return { response, chips, updates };
  },

  generateScripts: (session: Session) => {
    const need = session.extracted.needs[0] || "得到尊重与理解";
    const event = session.extracted.eventSummary || "最近发生的摩擦";

    // Simple script generator based on extracted info
    return {
      gentle: `“我想和你聊聊关于${event}。其实我当时感到挺难受的，因为我挺看重你的${need}。我们能不能试着换种方式交流？”`,
      firm: `“关于${event}，我希望你能明白，我的${need}对我非常重要。如果能得到你的重视，我会感觉好很多。”`,
      short: `“关于${event}，我现在的核心需求是${need}，希望能得到你的回应。”`
    };
  }
};

function getFocusName(focus: IPTFocus): string {
  const map = {
    [IPTFocus.DISPUTES]: '人际冲突',
    [IPTFocus.TRANSITION]: '角色转变',
    [IPTFocus.GRIEF]: '哀伤处理',
    [IPTFocus.DEFICITS]: '社交孤立',
    [IPTFocus.UNCERTAIN]: '关系困扰'
  };
  return map[focus];
}

