  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [session.messages]);

  const handleSend = (text: string) => {
    if (!text.trim()) return;

    // Special handling for end chips
    if (text === "查看话术") { onNavigate('coach'); return; }
    if (text === "查看计划") { onNavigate('action'); return; }
    if (text === "结束咨询") { onNavigate('home'); return; }

    const risk = identifyRisk(text);
    if (risk >= RiskLevel.L2) {
      onShowSafety();
    }

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now(),
    };

    const nextMessages = [...session.messages, userMsg];

    // Simulate AI processing
    setTimeout(() => {
      const { response, chips, updates } = iptEngine.generateResponse(session, text);
      const aiMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'ai',
        content: response,
        timestamp: Date.now(),
        chips: chips,
      };

      let nextStep = session.step;
      if (session.step < 9) nextStep += 1;

      updateSession({
        messages: [...nextMessages, aiMsg],
        step: nextStep,
        riskLevel: Math.max(session.riskLevel, risk),
        ...updates
      });
    }, 600);

    updateSession({ messages: nextMessages });
    setInput('');
  };

  return (
    <div className="flex flex-col h-full bg-slate-50/50">
      {/* Step Header */}
      <div className="bg-white px-6 py-4 border-b border-slate-100">
        <div className="flex items-center justify-between mb-3">
          <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider ${session.step >= 9 ? 'bg-green-50 text-green-600' : 'bg-indigo-50 text-indigo-600'}`}>
            {session.step >= 9 ? '已完成' : `STEP ${session.step} / 8`}
          </span>
          <span className="text-xs font-medium text-slate-800">{stepInfo.name}</span>
        </div>
        <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
          <div 
            className={`${session.step >= 9 ? 'bg-green-500' : 'bg-indigo-600'} h-full transition-all duration-500 ease-out`} 
            style={{ width: `${(Math.min(session.step, 8) / 8) * 100}%` }}
          />
        </div>
        <div className="mt-3 flex items-start gap-2">
          {session.step >= 9 ? <CheckCircle size={14} className="text-green-500 mt-0.5" /> : <Info size={14} className="text-slate-400 mt-0.5 flex-shrink-0" />}
          <p className="text-xs text-slate-500 leading-normal">{stepInfo.goal}</p>
        </div>
      </div>

      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
        {session.messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed animate-in fade-in slide-in-from-bottom-2 ${
              m.role === 'user' 
                ? 'bg-indigo-600 text-white shadow-md rounded-br-none' 
                : 'bg-white text-slate-800 border border-slate-100 shadow-sm rounded-bl-none'
            }`}>
              {m.content}
              {m.chips && m.role === 'ai' && (
                <div className="mt-4 flex flex-wrap gap-2">
                  {m.chips.map((chip, idx) => (
                    <button
                      key={idx}
                      onClick={() => handleSend(chip)}
                      className="text-xs bg-slate-50 text-slate-600 border border-slate-100 px-3 py-1.5 rounded-xl hover:bg-slate-100 hover:text-slate-900 transition-colors"
                    >
                      {chip}
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Input */}
      {session.step < 9 && (
        <div className="p-4 bg-white border-t border-slate-100">
          <div className="relative">
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="在这里输入您的回应..."
              rows={1}
              className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-3 px-4 pr-12 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-100 transition-all resize-none"
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSend(input);
                }
              }}
            />
            <button
              onClick={() => handleSend(input)}
              disabled={!input.trim()}
              className="absolute right-2 top-1.5 p-2 bg-slate-900 text-white rounded-xl disabled:opacity-30 transition-opacity"
            >
              <Send size={16} />
            </button>
          </div>
          <div className="mt-3 flex justify-between items-center px-1">
            <p className="text-[10px] text-slate-400">输入您的真实感受，我们会协助您拆解</p>
            <button onClick={() => handleSend("我想不清楚，给我点提示")} className="text-[10px] font-semibold text-indigo-600 hover:underline">
              跳过此步
            </button>
          </div>
        </div>
      )}

      {session.step >= 9 && (
        <div className="p-4 bg-white border-t border-slate-100 text-center">
           <p className="text-xs text-slate-400 mb-2">本次引导已完成</p>
           <div className="flex gap-2 justify-center">
              <button onClick={() => onNavigate('coach')} className="px-4 py-2 bg-indigo-50 text-indigo-600 rounded-xl text-xs font-semibold border border-indigo-100">查看话术建议</button>
              <button onClick={() => onNavigate('action')} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-xs font-semibold">查看行动计划</button>
           </div>
        </div>
      )}
    </div>
  );
};

