import { IPTFocus, Session, Message } from '../types';

const STEP_DATA = [
  { step: 1, name: '目标定义', goal: '明确我们今天要解决的核心关系问题。' },
  { step: 2, name: '事件澄清', goal: '还原最近一次让您感到不适的互动细节。' },
  { step: 3, name: '情绪定位', goal: '识别在那一刻，您最真实的情绪反应。' },
  { step: 4, name: '需求澄清', goal: '挖掘情绪背后的心理需求是什么。' },
  { step: 5, name: '角色与期待', goal: '分析您与对方在这个关系中的角色期待。' },
  { step: 6, name: '循环识别', goal: '观察这种互动是否在重复某种模式。' },
  { step: 7, name: '沟通彩排', goal: '尝试用新的表达方式来改写局面。' },
  { step: 8, name: '行动计划', goal: '确定未来24小时内的一个微小行动。' },
  { step: 9, name: '咨询总结', goal: '回顾本次梳理的重点与下一步行动。' },
];

export const iptEngine = {
  getStepInfo: (step: number) => STEP_DATA[Math.min(step - 1, 8)],

  generateResponse: (session: Session, userInput: string): { response: string; chips?: string[]; updates?: Partial<Session> } => {
    const { step, iptFocus } = session;
    let response = "";
    let chips: string[] = [];
    let updates: Partial<Session> = {
      extracted: { ...session.extracted }
    };

    // --- Dynamic Extraction Logic ---
    if (step === 1) {
       updates.goal = userInput;
    } else if (step === 2) {
       updates.extracted!.eventSummary = userInput;
    } else if (step === 3) {
       updates.extracted!.emotions = [userInput];
    } else if (step === 4) {
       updates.extracted!.needs = [userInput];
    } else if (step === 8) {
       updates.actionPlan = {
         task: userInput,
         successCriteria: `能够清晰表达出“${session.extracted.needs[0] || '我的想法'}”且没有引发新的争吵`,
         backupPlan: "如果对方拒绝沟通，我将保持沉默并记录下那一刻的感受，明天再尝试。",
         completed: false
       };
    }

    switch (step) {
      case 1:
        response = `针对${getFocusName(iptFocus)}，您希望通过谈话达到什么目标？（如：缓和关系、明确边界或寻求理解）`;
        chips = ["缓和紧张气氛", "明确表达我的需求", "决定是否暂时离开", "停止无谓的争执"];
        break;
      case 2:
        response = "明白了。请简要描述最近发生的一个具体片段：当时对方说了什么？您的反应是？";
        chips = ["昨天晚上的争吵", "对方一直在冷战", "因为小事引发的冲突", "我想不起来细节"];
        break;
      case 3:
        response = "在那段互动中，您最强烈的情绪感受是什么？（例如：委屈、愤怒、被忽视、无力感等）";
        chips = ["强烈的委屈感", "莫名的愤怒", "一种深深的挫败感", "感到自己被忽视了"];
        break;
      case 4:
        response = `这种“${userInput}”的情绪在告诉我们，您当时最真实的需求是什么？您最渴望从对方那里得到什么？`;
        chips = ["我渴望被尊重", "我需要对方的理解", "我需要一些个人空间", "我需要看到改变的承诺"];
        break;
      case 5:
        response = "在您看来，您希望对方扮演什么角色（如支持者、共情者）？而他目前的表现像什么？";
        chips = ["希望他是我的支持者", "他表现得像个评判者", "希望我们是平等的同盟", "角色已经完全错位了"];
        break;
      case 6:
        response = "这种“不满足”的互动模式以前发生过吗？是不是一旦对方开始某项行为，您就会产生这种反应？";
        chips = ["几乎每次都这样", "这是我们的老剧本了", "偶尔发生，但很痛苦", "这是第一次深刻意识到"];
        break;
      case 7:
        response = "如果我们要打破这个循环，尝试一种新的表达方式。您想试试看我为您生成的建议话术吗？";
        chips = ["请给我建议话术", "我想试试温和的表达", "我需要表现得更坚定", "跳过，直接定计划"];
        break;
      case 8:
        response = "为了改变现状，在未来24小时内，您可以做的一个“最小行动”是什么？（不要压力，只要一小步）";
        chips = ["给他发个简短微信", "今晚先保持沉默观察", "主动发起一次正式谈话", "把我的感受写在纸上"];
        break;
      case 9:
        const emotion = session.extracted.emotions[0] || "复杂";
        const need = session.extracted.needs[0] || "被理解";
        response = `【咨询总结】我们今天理清了：您感到“${emotion}”，核心是因为“${need}”没有得到满足。

我已经为您在“教练”页生成了专属话术，在“计划”页制定了行动方案。您现在感觉如何？`;
        chips = ["查看话术建议", "查看行动计划", "重新开始咨询"];
        break;
      default:
        response = "本次咨询已结束，希望这些建议能帮到您。";
    }

    return { response, chips, updates };
  },

  generateScripts: (session: Session) => {
    const need = session.extracted.needs[0] || "我的真实需求";
    const emotion = session.extracted.emotions[0] || "挺难受的";
    const event = session.extracted.eventSummary || "刚才那件事";

    return {
      gentle: `“我想和你聊聊关于${event}。其实我当时感到${emotion}，因为我真的很看重${need}。我们能不能试着换种方式？”`,
      firm: `“关于${event}，我希望你能明白，${need}对我来说非常重要。我不能接受那种被忽视的感觉，希望你能尊重我的边界。”`,
      short: `“关于这件事，我现在的感受是${emotion}，我最需要的是${need}。”`
    };
  }
};

function getFocusName(focus: IPTFocus): string {
  const map = {
    [IPTFocus.DISPUTES]: '人际冲突',
    [IPTFocus.TRANSITION]: '角色转变',
    [IPTFocus.GRIEF]: '哀伤处理',
    [IPTFocus.DEFICITS]: '社交孤立',
    [IPTFocus.UNCERTAIN]: '关系困扰'
  };
  return map[focus];
}

import React, { useState, useEffect, useRef } from 'react';
import { Session, Message, RiskLevel } from '../types';
import { iptEngine } from '../lib/iptEngine';
import { identifyRisk } from '../lib/risk';
import { Send, ChevronRight, Info, CheckCircle, RotateCcw } from 'lucide-react';

interface SessionPageProps {
  session: Session;
  updateSession: (updates: Partial<Session>) => void;
  onShowSafety: () => void;
  onNavigate: (view: any) => void;
  onRestart: () => void;
}

const SessionPage: React.FC<SessionPageProps> = ({ session, updateSession, onShowSafety, onNavigate, onRestart }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);
  const stepInfo = iptEngine.getStepInfo(session.step);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [session.messages]);

  const handleSend = (text: string) => {
    if (!text.trim()) return;

    // Special handling for navigation and restart chips
    if (text === "查看话术建议") { onNavigate('coach'); return; }
    if (text === "查看行动计划") { onNavigate('action'); return; }
    if (text === "重新开始咨询") { onRestart(); return; }
    if (text === "结束咨询") { onNavigate('home'); return; }

    const risk = identifyRisk(text);
    if (risk >= RiskLevel.L2) {
      onShowSafety();
    }

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now(),
    };

    const nextMessages = [...session.messages, userMsg];

    // Simulate AI processing
    setTimeout(() => {
      const { response, chips, updates } = iptEngine.generateResponse(session, text);
      const aiMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'ai',
        content: response,
        timestamp: Date.now(),
        chips: chips,
      };

      let nextStep = session.step;
      if (session.step < 9) nextStep += 1;

      updateSession({
        messages: [...nextMessages, aiMsg],
        step: nextStep,
        riskLevel: Math.max(session.riskLevel, risk),
        ...updates
      });
    }, 600);

    updateSession({ messages: nextMessages });
    setInput('');
  };

  return (
    <div className="flex flex-col h-full bg-slate-50/50">
      {/* Step Header */}
      <div className="bg-white px-6 py-4 border-b border-slate-100 shadow-sm">
        <div className="flex items-center justify-between mb-3">
          <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider ${session.step >= 9 ? 'bg-green-50 text-green-600' : 'bg-indigo-50 text-indigo-600'}`}>
            {session.step >= 9 ? '咨询完成' : `第 ${session.step} 步 / 共 8 步`}
          </span>
          <span className="text-xs font-semibold text-slate-700">{stepInfo.name}</span>
        </div>
        <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
          <div 
            className={`${session.step >= 9 ? 'bg-green-500' : 'bg-indigo-600'} h-full transition-all duration-700 ease-in-out`} 
            style={{ width: `${(Math.min(session.step, 8) / 8) * 100}%` }}
          />
        </div>
        <div className="mt-3 flex items-start gap-2">
          {session.step >= 9 ? <CheckCircle size={14} className="text-green-500 mt-0.5 flex-shrink-0" /> : <Info size={14} className="text-slate-400 mt-0.5 flex-shrink-0" />}
          <p className="text-xs text-slate-500 leading-normal font-medium">{stepInfo.goal}</p>
        </div>
      </div>

      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar bg-slate-50/30">
        {session.messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed animate-in fade-in slide-in-from-bottom-2 ${
              m.role === 'user' 
                ? 'bg-indigo-600 text-white shadow-md rounded-br-none' 
                : 'bg-white text-slate-800 border border-slate-100 shadow-sm rounded-bl-none'
            }`}>
              {m.content}
              {m.chips && m.role === 'ai' && (
                <div className="mt-4 flex flex-wrap gap-2">
                  {m.chips.map((chip, idx) => (
                    <button
                      key={idx}
                      onClick={() => handleSend(chip)}
                      className="text-xs bg-white text-indigo-600 border border-indigo-100 px-3 py-2 rounded-xl hover:bg-indigo-50 hover:shadow-sm transition-all font-medium"
                    >
                      {chip}
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Input / Footer Area */}
      <div className="bg-white border-t border-slate-100 shadow-[0_-4px_12px_rgba(0,0,0,0.02)]">
        {session.step < 9 ? (
          <div className="p-4">
            <div className="relative">
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="在此输入您的回复..."
                rows={1}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-3 px-4 pr-12 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-indigo-200 transition-all resize-none placeholder:text-slate-400"
                style={{ color: '#0f172a' }} // Forced visible color
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSend(input);
                  }
                }}
              />
              <button
                onClick={() => handleSend(input)}
                disabled={!input.trim()}
                className="absolute right-2 top-1.5 p-2.5 bg-slate-900 text-white rounded-xl disabled:opacity-20 hover:bg-slate-800 transition-colors shadow-sm"
              >
                <Send size={16} />
              </button>
            </div>
            <div className="mt-3 flex justify-between items-center px-1">
              <p className="text-[10px] text-slate-400 font-medium">坦诚输入有助于更精准的梳理</p>
              <button onClick={() => handleSend("我想不清楚，给我点提示")} className="text-[10px] font-bold text-indigo-600 hover:text-indigo-700">
                跳过此步
              </button>
            </div>
          </div>
        ) : (
          <div className="p-6 text-center animate-in fade-in slide-in-from-bottom-2">
             <div className="bg-green-50 p-3 rounded-2xl mb-4 inline-flex">
                <CheckCircle className="text-green-500" size={20} />
             </div>
             <p className="text-sm font-semibold text-slate-900 mb-4">本次结构化咨询已成功闭环</p>
             <div className="grid grid-cols-2 gap-3 mb-4">
                <button onClick={() => onNavigate('coach')} className="px-4 py-3 bg-white text-indigo-600 rounded-2xl text-xs font-bold border border-indigo-100 shadow-sm hover:bg-indigo-50 transition-colors">查看话术建议</button>
                <button onClick={() => onNavigate('action')} className="px-4 py-3 bg-indigo-600 text-white rounded-2xl text-xs font-bold shadow-md hover:bg-indigo-700 transition-colors">查看行动计划</button>
             </div>
             <button 
                onClick={onRestart}
                className="flex items-center justify-center gap-2 mx-auto text-xs text-slate-400 hover:text-slate-600 py-2 transition-colors font-medium"
              >
                <RotateCcw size={14} />
                清空当前进度，重新开始
              </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default SessionPage;

import React, { useState, useEffect } from 'react';
import { Session, IPTFocus, AppView, RiskLevel } from './types';
import { storage } from './lib/storage';
import Layout from './components/Layout';
import Home from './pages/Home';
import SessionPage from './pages/SessionPage';
import CoachPage from './pages/CoachPage';
import ActionPage from './pages/ActionPage';
import HistoryPage from './pages/HistoryPage';
import SafetySheet from './components/SafetySheet';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<AppView>('home');
  const [currentSession, setCurrentSession] = useState<Session | null>(null);
  const [showSafety, setShowSafety] = useState(false);

  // Initialize view from hash or state
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash.replace('#', '') as AppView;
      if (['home', 'session', 'coach', 'action', 'history'].includes(hash)) {
        setActiveView(hash);
      }
    };
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  const navigateTo = (view: AppView) => {
    setActiveView(view);
    window.location.hash = view;
  };

  const startNewSession = (focus: IPTFocus) => {
    const newSession: Session = {
      id: Date.now().toString(),
      createdAt: Date.now(),
      updatedAt: Date.now(),
      iptFocus: focus,
      riskLevel: RiskLevel.L0,
      step: 1,
      messages: [
        {
          id: 'welcome',
          role: 'ai',
          content: `好的，我们开始探讨${getFocusName(focus)}。为了有效利用这次时间，我们先从定义目标开始。您最想解决的问题是什么？`,
          timestamp: Date.now(),
          chips: ["我想缓和冲突", "我需要表达我的不满", "我希望更了解对方", "我不确定目标"]
        }
      ],
      extracted: {
        emotions: [],
        needs: []
      }
    };
    setCurrentSession(newSession);
    storage.saveCurrentSession(newSession);
    navigateTo('session');
  };

  const restartSession = () => {
    if (currentSession) {
      startNewSession(currentSession.iptFocus);
    } else {
      navigateTo('home');
    }
  };

  const updateSession = (updates: Partial<Session>) => {
    if (!currentSession) return;
    const updated = { ...currentSession, ...updates, updatedAt: Date.now() };
    setCurrentSession(updated);
    storage.saveCurrentSession(updated);
  };

  const handleSelectHistory = (session: Session) => {
    setCurrentSession(session);
    navigateTo('session');
  };

  const handleClearHistory = () => {
    storage.clearAll();
    setCurrentSession(null);
    navigateTo('home');
  };

  const getPageTitle = () => {
    switch (activeView) {
      case 'home': return '选择困扰领域';
      case 'session': return '深度咨询中';
      case 'coach': return '话术实验室';
      case 'action': return '行动清单';
      case 'history': return '咨询档案';
      default: return 'IPT AI';
    }
  };

  return (
    <Layout 
      activeView={activeView} 
      onNavigate={navigateTo} 
      title={getPageTitle()}
    >
      {activeView === 'home' && <Home onStart={startNewSession} />}

      {activeView === 'session' && currentSession && (
        <SessionPage 
          session={currentSession} 
          updateSession={updateSession} 
          onShowSafety={() => setShowSafety(true)}
          onNavigate={navigateTo}
          onRestart={restartSession}
        />
      )}

      {activeView === 'coach' && currentSession && (
        <CoachPage session={currentSession} />
      )}

      {activeView === 'action' && currentSession && (
        <ActionPage session={currentSession} updateSession={updateSession} />
      )}

      {activeView === 'history' && (
        <HistoryPage 
          onSelect={handleSelectHistory} 
          onClear={handleClearHistory} 
        />
      )}

      {/* Placeholder for no active session */}
      {['session', 'coach', 'action'].includes(activeView) && !currentSession && (
        <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-4">
          <div className="p-4 bg-slate-50 rounded-full text-slate-300">
            <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
            </svg>
          </div>
          <div>
            <h3 className="text-slate-900 font-semibold">未检测到活动会话</h3>
            <p className="text-slate-400 text-sm">请先从首页开始一个新的 IPT 咨询流程。</p>
          </div>
          <button onClick={() => navigateTo('home')} className="px-6 py-2 bg-indigo-600 text-white rounded-2xl text-sm font-medium">
            去首页
          </button>
        </div>
      )}

      <SafetySheet isOpen={showSafety} onClose={() => setShowSafety(false)} />
    </Layout>
  );
};

function getFocusName(focus: IPTFocus): string {
  const map = {
    [IPTFocus.DISPUTES]: '人际冲突',
    [IPTFocus.TRANSITION]: '角色转变',
    [IPTFocus.GRIEF]: '哀伤处理',
    [IPTFocus.DEFICITS]: '社交孤立',
    [IPTFocus.UNCERTAIN]: '关系困扰'
  };
  return map[focus];
}

export default App;

import { IPTFocus, Session, Message } from '../types';

const STEP_DATA = [
  { step: 1, name: '目标定义', goal: '明确我们今天要解决的核心关系问题。' },
  { step: 2, name: '事件澄清', goal: '还原最近一次让您感到不适的互动细节。' },
  { step: 3, name: '情绪定位', goal: '识别在那一刻，您最真实的情绪反应。' },
  { step: 4, name: '需求澄清', goal: '挖掘情绪背后的心理需求是什么。' },
  { step: 5, name: '角色与期待', goal: '分析您与对方在这个关系中的角色期待。' },
  { step: 6, name: '循环识别', goal: '观察这种互动是否在重复某种模式。' },
  { step: 7, name: '沟通彩排', goal: '尝试用新的表达方式来改写局面。' },
  { step: 8, name: '行动计划', goal: '确定未来24小时内的一个微小行动。' },
  { step: 9, name: '咨询总结', goal: '回顾本次梳理的重点与下一步行动。' },
  { step: 10, name: '持续支持', goal: '基于已梳理的逻辑，陪伴您进行深度探索。' },
];

export const iptEngine = {
  getStepInfo: (step: number) => STEP_DATA[Math.min(step - 1, 9)],

  generateResponse: (session: Session, userInput: string): { response: string; chips?: string[]; updates?: Partial<Session> } => {
    const { step, iptFocus } = session;
    let response = "";
    let chips: string[] = [];
    let updates: Partial<Session> = {
      extracted: { ...session.extracted }
    };

    // --- Dynamic Extraction Logic ---
    if (step === 1) updates.goal = userInput;
    else if (step === 2) updates.extracted!.eventSummary = userInput;
    else if (step === 3) updates.extracted!.emotions = [userInput];
    else if (step === 4) updates.extracted!.needs = [userInput];
    else if (step === 8) {
       updates.actionPlan = {
         task: userInput,
         successCriteria: `能够清晰表达出“${session.extracted.needs[0] || '我的想法'}”且没有引发新的争吵`,
         backupPlan: "如果对方拒绝沟通，我将保持沉默并记录下那一刻的感受，明天再尝试。",
         completed: false
       };
    }

    if (step >= 10) {
      return generatePostSessionResponse(session, userInput);
    }

    switch (step) {
      case 1:
        response = `针对${getFocusName(iptFocus)}，您希望通过谈话达到什么目标？（如：缓和关系、明确边界或寻求理解）`;
        chips = ["缓和紧张气氛", "明确表达我的需求", "决定是否暂时离开", "停止无谓的争执"];
        break;
      case 2:
        response = "明白了。请简要描述最近发生的一个具体片段：当时对方说了什么？您的反应是？";
        chips = ["昨天晚上的争吵", "对方一直在冷战", "因为小事引发的冲突", "我想不起来细节"];
        break;
      case 3:
        response = "在那段互动中，您最强烈的情绪感受是什么？（例如：委屈、愤怒、被忽视、无力感等）";
        chips = ["强烈的委屈感", "莫名的愤怒", "一种深深的挫败感", "感到自己被忽视了"];
        break;
      case 4:
        response = `这种“${userInput}”的情绪在告诉我们，您当时最真实的需求是什么？您最渴望从对方那里得到什么？`;
        chips = ["我渴望被尊重", "我需要对方的理解", "我需要一些个人空间", "我需要看到改变的承诺"];
        break;
      case 5:
        response = "在您看来，您希望对方扮演什么角色（如支持者、共情者）？而他目前的表现像什么？";
        chips = ["希望他是我的支持者", "他表现得像个评判者", "希望我们是平等的同盟", "角色已经完全错位了"];
        break;
      case 6:
        response = "这种“不满足”的互动模式以前发生过吗？是不是一旦对方开始某项行为，您就会产生这种反应？";
        chips = ["几乎每次都这样", "这是我们的老剧本了", "偶尔发生，但很痛苦", "这是第一次深刻意识到"];
        break;
      case 7:
        response = "如果我们要打破这个循环，尝试一种新的表达方式。您想试试看我为您生成的建议话术吗？";
        chips = ["请给我建议话术", "我想试试温和的表达", "我需要表现得更坚定", "跳过，直接定计划"];
        break;
      case 8:
        response = "为了改变现状，在未来24小时内，您可以做的一个“最小行动”是什么？（不要压力，只要一小步）";
        chips = ["给他发个简短微信", "今晚先保持沉默观察", "主动发起一次正式谈话", "把我的感受写在纸上"];
        break;
      case 9:
        const emotion = session.extracted.emotions[0] || "复杂";
        const need = session.extracted.needs[0] || "被理解";
        response = `【咨询总结】我们今天理清了：您感到“${emotion}”，核心是因为“${need}”没有得到满足。

结构化梳理已完成。您可以继续和我聊聊，或者点击下方按钮查看方案。`;
        chips = ["查看话术建议", "查看行动计划", "我想再多聊聊", "重新开始咨询"];
        break;
      default:
        response = "本次咨询已结束，希望这些建议能帮到您。";
    }

    return { response, chips, updates };
  },

  generateScripts: (session: Session) => {
    const need = session.extracted.needs[0] || "我的真实需求";
    const emotion = session.extracted.emotions[0] || "挺难受的";
    const event = session.extracted.eventSummary || "刚才那件事";

    return {
      gentle: `“我想和你聊聊关于${event}。其实我当时感到${emotion}，因为我真的很看重${need}。我们能不能试着换种方式？”`,
      firm: `“关于${event}，我希望你能明白，${need}对我来说非常重要。我不能接受那种被忽视的感觉，希望你能尊重我的边界。”`,
      short: `“关于这件事，我现在的感受是${emotion}，我最需要的是${need}。”`
    };
  }
};

function generatePostSessionResponse(session: Session, input: string): { response: string; chips?: string[] } {
  const need = session.extracted.needs[0] || "心理需求";
  const emotion = session.extracted.emotions[0] || "情绪";
  const focus = getFocusName(session.iptFocus);

  const templates = [
    `关于“${input}”，我能感觉到您还在消化中。回想起刚才提到的“${need}”，您觉得这个细节是否再次触动了它？`,
    `理解您的想法。在${focus}的过程中，面对“${emotion}”是很不容易的。接下来的行动，您觉得自己准备好了吗？`,
    `这是一个很细微的观察。如果我们坚持“${need}”这个原则，在接下来的对话中，您会如何回应？`,
    `我听到了。很多时候，关系中的困扰就是这样反复。我们已经识别出了模式，这就是一种进步。您想具体聊聊哪一部分？`
  ];

  const response = templates[Math.floor(Math.random() * templates.length)];
  return { 
    response, 
    chips: ["我还没准备好行动", "再给我些话术启发", "感觉好多了", "结束并重新开始"] 
  };
}

function getFocusName(focus: IPTFocus): string {
  const map = {
    [IPTFocus.DISPUTES]: '人际冲突',
    [IPTFocus.TRANSITION]: '角色转变',
    [IPTFocus.GRIEF]: '哀伤处理',
    [IPTFocus.DEFICITS]: '社交孤立',
    [IPTFocus.UNCERTAIN]: '关系困扰'
  };
  return map[focus];
}

import React, { useState, useEffect, useRef } from 'react';
import { Session, Message, RiskLevel } from '../types';
import { iptEngine } from '../lib/iptEngine';
import { identifyRisk } from '../lib/risk';
import { Send, ChevronRight, Info, CheckCircle, RotateCcw, MessageCircle } from 'lucide-react';

interface SessionPageProps {
  session: Session;
  updateSession: (updates: Partial<Session>) => void;
  onShowSafety: () => void;
  onNavigate: (view: any) => void;
  onRestart: () => void;
}

const SessionPage: React.FC<SessionPageProps> = ({ session, updateSession, onShowSafety, onNavigate, onRestart }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);
  const stepInfo = iptEngine.getStepInfo(session.step);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [session.messages]);

  const handleSend = (text: string) => {
    if (!text.trim()) return;

    // Special handling for navigation and restart chips
    if (text === "查看话术建议" || text === "再给我些话术启发") { onNavigate('coach'); return; }
    if (text === "查看行动计划") { onNavigate('action'); return; }
    if (text === "重新开始咨询" || text === "结束并重新开始") { onRestart(); return; }
    if (text === "结束咨询") { onNavigate('home'); return; }
    if (text === "我想再多聊聊") { 
      // Just advance to continuous mode silently
      text = "我想就刚才聊到的内容再深入谈谈。";
    }

    const risk = identifyRisk(text);
    if (risk >= RiskLevel.L2) {
      onShowSafety();
    }

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now(),
    };

    const nextMessages = [...session.messages, userMsg];

    // Simulate AI processing
    setTimeout(() => {
      const { response, chips, updates } = iptEngine.generateResponse(session, text);
      const aiMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'ai',
        content: response,
        timestamp: Date.now(),
        chips: chips,
      };

      let nextStep = session.step;
      if (session.step < 10) nextStep += 1;

      updateSession({
        messages: [...nextMessages, aiMsg],
        step: nextStep,
        riskLevel: Math.max(session.riskLevel, risk),
        ...updates
      });
    }, 600);

    updateSession({ messages: nextMessages });
    setInput('');
  };

  return (
    <div className="flex flex-col h-full bg-slate-50/50">
      {/* Step Header */}
      <div className="bg-white px-6 py-4 border-b border-slate-100 shadow-sm transition-all duration-300">
        <div className="flex items-center justify-between mb-3">
          <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider transition-colors ${session.step >= 9 ? 'bg-teal-50 text-teal-600' : 'bg-indigo-50 text-indigo-600'}`}>
            {session.step >= 10 ? '持续支持模式' : session.step === 9 ? '咨询总结' : `第 ${session.step} 步 / 共 8 步`}
          </span>
          <span className="text-xs font-semibold text-slate-700">{stepInfo.name}</span>
        </div>
        <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
          <div 
            className={`${session.step >= 9 ? 'bg-teal-500' : 'bg-indigo-600'} h-full transition-all duration-700 ease-in-out`} 
            style={{ width: `${(Math.min(session.step, 8) / 8) * 100}%` }}
          />
        </div>
        <div className="mt-3 flex items-start gap-2">
          {session.step >= 10 ? <MessageCircle size={14} className="text-teal-500 mt-0.5 flex-shrink-0" /> : session.step === 9 ? <CheckCircle size={14} className="text-teal-500 mt-0.5 flex-shrink-0" /> : <Info size={14} className="text-slate-400 mt-0.5 flex-shrink-0" />}
          <p className="text-xs text-slate-500 leading-normal font-medium">{stepInfo.goal}</p>
        </div>
      </div>

      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar bg-slate-50/30">
        {session.messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed animate-in fade-in slide-in-from-bottom-2 ${
              m.role === 'user' 
                ? 'bg-indigo-600 text-white shadow-md rounded-br-none' 
                : 'bg-white text-slate-800 border border-slate-100 shadow-sm rounded-bl-none'
            }`}>
              {m.content}
              {m.chips && m.role === 'ai' && (
                <div className="mt-4 flex flex-wrap gap-2">
                  {m.chips.map((chip, idx) => (
                    <button
                      key={idx}
                      onClick={() => handleSend(chip)}
                      className="text-xs bg-white text-indigo-600 border border-indigo-100 px-3 py-2 rounded-xl hover:bg-indigo-50 hover:shadow-sm transition-all font-medium"
                    >
                      {chip}
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Input / Footer Area - Always visible now */}
      <div className="bg-white border-t border-slate-100 shadow-[0_-4px_12px_rgba(0,0,0,0.02)]">
        {/* Conditional Summary Overlay for Step 9 Only */}
        {session.step === 9 && (
           <div className="px-6 py-4 bg-teal-50/50 border-b border-teal-100 flex items-center justify-between">
              <p className="text-[11px] text-teal-700 font-semibold">✨ 结构化流程已闭环，您可在此继续畅聊</p>
              <div className="flex gap-2">
                 <button onClick={() => onNavigate('coach')} className="text-[10px] bg-white border border-teal-100 px-2 py-1 rounded-lg text-teal-600 font-bold">查看话术</button>
                 <button onClick={() => onNavigate('action')} className="text-[10px] bg-teal-600 text-white px-2 py-1 rounded-lg font-bold">查看计划</button>
              </div>
           </div>
        )}

        <div className="p-4">
          <div className="relative">
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={session.step >= 9 ? "继续输入以深入探索..." : "在此输入您的回复..."}
              rows={1}
              className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-3 px-4 pr-12 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-indigo-200 transition-all resize-none placeholder:text-slate-400"
              style={{ color: '#0f172a' }}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSend(input);
                }
              }}
            />
            <button
              onClick={() => handleSend(input)}
              disabled={!input.trim()}
              className="absolute right-2 top-1.5 p-2.5 bg-slate-900 text-white rounded-xl disabled:opacity-20 hover:bg-slate-800 transition-colors shadow-sm"
            >
              <Send size={16} />
            </button>
          </div>
