import { GoogleGenAI, Type } from "@google/genai";
import { IPTFocus, Session } from '../types';

// Initialize the Google GenAI client with named apiKey parameter using process.env.API_KEY directly.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const STEP_DATA = [
  { step: 1, name: '目标定义', goal: '明确我们今天要解决的核心关系问题。' },
  { step: 2, name: '事件澄清', goal: '还原最近一次让您感到不适的互动细节。' },
  { step: 3, name: '情绪定位', goal: '识别在那一刻，您最真实的情绪反应。' },
  { step: 4, name: '需求澄清', goal: '挖掘情绪背后的心理需求是什么。' },
  { step: 5, name: '角色与期待', goal: '分析您与对方在这个关系中的角色期待。' },
  { step: 6, name: '循环识别', goal: '观察这种互动是否在重复某种模式。' },
  { step: 7, name: '沟通彩排', goal: '尝试用新的表达方式来改写局面。' },
  { step: 8, name: '行动计划', goal: '确定未来24小时内的一个微小行动。' },
  { step: 9, name: '咨询总结', goal: '回顾本次梳理的重点与下一步行动。' },
  { step: 10, name: '持续支持', goal: '基于已梳理的逻辑，陪伴您进行深度探索。' },
];

export const iptEngine = {
  getStepInfo: (step: number) => STEP_DATA[Math.min(step - 1, 9)],

  /**
   * Generates a high-quality response using Gemini 3 Pro for advanced counseling reasoning.
   */
  generateResponse: async (session: Session, userInput: string): Promise<{ response: string; chips?: string[]; updates?: Partial<Session> }> => {
    const { step, iptFocus } = session;
    const stepInfo = iptEngine.getStepInfo(step);

    // Construct the prompt for the counseling session
    const prompt = `You are a professional IPT (Interpersonal Psychotherapy) counselor. 
    Focus: ${getFocusName(iptFocus)}
    Context: Step ${step} (${stepInfo.name}) - Goal: ${stepInfo.goal}

    Recent Chat History:
    ${session.messages.slice(-6).map(m => `${m.role === 'ai' ? 'Counselor' : 'User'}: ${m.content}`).join('\n')}

    User's latest input: "${userInput}"

    Requirements:
    1. Respond in Chinese with deep empathy and professional counseling guidance.
    2. Guide the user through the 8-step IPT process.
    3. Extract/Update session information (emotions, needs, etc.) from the input.
    4. Provide exactly 3-4 short, helpful response 'chips' (buttons) for the user.
    5. Output the result in valid JSON format.
    `;

    try {
      // Use Gemini 3 Pro for complex text reasoning tasks like counseling.
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              response: { type: Type.STRING, description: "The empathic verbal response from the counselor." },
              chips: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Suggestions for user buttons." },
              updates: {
                type: Type.OBJECT,
                properties: {
                  goal: { type: Type.STRING },
                  extracted: {
                    type: Type.OBJECT,
                    properties: {
                      eventSummary: { type: Type.STRING },
                      emotions: { type: Type.ARRAY, items: { type: Type.STRING } },
                      needs: { type: Type.ARRAY, items: { type: Type.STRING } },
                      pattern: { type: Type.STRING },
                    }
                  }
                }
              }
            },
            required: ["response", "chips"]
          }
        }
      });

      // Extract generated text from the property as per best practices.
      const parsed = JSON.parse(response.text || '{}');

      // Additional logic for step 8 action plan construction
      if (step === 8 && userInput) {
          parsed.updates = parsed.updates || {};
          parsed.updates.actionPlan = {
              task: userInput,
              successCriteria: "清晰表达了自己的核心需求且没有发生争执",
              backupPlan: "如果沟通受挫，先退后一步保持冷静，明日再谈",
              completed: false
          };
      }

      return {
        response: parsed.response || "我能感觉到这不容易。您愿意多和我分享一些关于刚才那个细节的感受吗？",
        chips: parsed.chips || ["我想继续聊聊", "可以给我一些建议吗？"],
        updates: parsed.updates || {}
      };
    } catch (error) {
      console.error("Gemini API processing error:", error);
      return { 
        response: "抱歉，我的思绪刚才有些中断。基于您现在的处境，您觉得我们最应该关注哪个方面？", 
        chips: ["情绪", "沟通方式", "接下来的行动"] 
      };
    }
  },

  generateScripts: (session: Session) => {
    const need = session.extracted.needs[0] || "我的真实需求";
    const emotion = session.extracted.emotions[0] || "感到挺困扰的";
    const event = session.extracted.eventSummary || "刚才那件事";

    return {
      gentle: `“我想和你聊聊关于${event}。其实我当时感到${emotion}，因为我真的很看重${need}。我们能不能试着换种方式？”`,
      firm: `“关于${event}，我希望你能明白，${need}对我来说非常重要。我不能接受那种被忽视的感觉，希望你能尊重我的边界。”`,
      short: `“关于这件事，我现在的感受是${emotion}，我最需要的是${need}。”`
    };
  }
};

function getFocusName(focus: IPTFocus): string {
  const map = {
    [IPTFocus.DISPUTES]: '人际冲突',
    [IPTFocus.TRANSITION]: '角色转变',
    [IPTFocus.GRIEF]: '哀伤处理',
    [IPTFocus.DEFICITS]: '社交孤立',
    [IPTFocus.UNCERTAIN]: '关系困扰'
  };
  return map[focus];
}

import React, { useState, useEffect, useRef } from 'react';
import { Session, Message, RiskLevel, AppView } from '../types';
import { iptEngine } from '../lib/iptEngine';
import { identifyRisk } from '../lib/risk';
import { Send, ChevronRight, Info, CheckCircle, RotateCcw, MessageCircle } from 'lucide-react';

interface SessionPageProps {
  session: Session;
  updateSession: (updates: Partial<Session>) => void;
  onShowSafety: () => void;
  onNavigate: (view: AppView) => void;
  onRestart: () => void;
}

const SessionPage: React.FC<SessionPageProps> = ({ session, updateSession, onShowSafety, onNavigate, onRestart }) => {
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);
  const stepInfo = iptEngine.getStepInfo(session.step);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [session.messages]);

  // Handle sending messages asynchronously to allow for real-time AI processing
  const handleSend = async (text: string) => {
    if (!text.trim()) return;

    // Special handling for navigation and restart chips
    if (text === "查看话术建议" || text === "再给我些话术启发") { onNavigate('coach'); return; }
    if (text === "查看行动计划") { onNavigate('action'); return; }
    if (text === "重新开始咨询" || text === "结束并重新开始") { onRestart(); return; }
    if (text === "结束咨询") { onNavigate('home'); return; }
    if (text === "我想再多聊聊") { 
      text = "我想就刚才聊到的内容再深入谈谈。";
    }

    const risk = identifyRisk(text);
    if (risk >= RiskLevel.L2) {
      onShowSafety();
    }

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now(),
    };

    const nextMessages = [...session.messages, userMsg];
    updateSession({ messages: nextMessages });
    setInput('');

    // Process using Gemini API asynchronously
    try {
      const { response, chips, updates } = await iptEngine.generateResponse(session, text);
      const aiMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'ai',
        content: response,
        timestamp: Date.now(),
        chips: chips,
      };

      let nextStep = session.step;
      if (session.step < 10) nextStep += 1;

      updateSession({
        messages: [...nextMessages, aiMsg],
        step: nextStep,
        riskLevel: Math.max(session.riskLevel, risk),
        ...updates
      });
    } catch (error) {
      console.error("Failed to process conversation response:", error);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50/50">
      {/* Step Header */}
      <div className="bg-white px-6 py-4 border-b border-slate-100 shadow-sm transition-all duration-300">
        <div className="flex items-center justify-between mb-3">
          <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider transition-colors ${session.step >= 9 ? 'bg-teal-50 text-teal-600' : 'bg-indigo-50 text-indigo-600'}`}>
            {session.step >= 10 ? '持续支持模式' : session.step === 9 ? '咨询总结' : `第 ${session.step} 步 / 共 8 步`}
          </span>
          <span className="text-xs font-semibold text-slate-700">{stepInfo.name}</span>
        </div>
        <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
          <div 
            className={`${session.step >= 9 ? 'bg-teal-500' : 'bg-indigo-600'} h-full transition-all duration-700 ease-in-out`} 
            style={{ width: `${(Math.min(session.step, 8) / 8) * 100}%` }}
          />
        </div>
        <div className="mt-3 flex items-start gap-2">
          {session.step >= 10 ? <MessageCircle size={14} className="text-teal-500 mt-0.5 flex-shrink-0" /> : session.step === 9 ? <CheckCircle size={14} className="text-teal-500 mt-0.5 flex-shrink-0" /> : <Info size={14} className="text-slate-400 mt-0.5 flex-shrink-0" />}
          <p className="text-xs text-slate-500 leading-normal font-medium">{stepInfo.goal}</p>
        </div>
      </div>

      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar bg-slate-50/30">
        {session.messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed animate-in fade-in slide-in-from-bottom-2 ${
              m.role === 'user' 
                ? 'bg-indigo-600 text-white shadow-md rounded-br-none' 
                : 'bg-white text-slate-800 border border-slate-100 shadow-sm rounded-bl-none'
            }`}>
              {m.content}
              {m.chips && m.role === 'ai' && (
                <div className="mt-4 flex flex-wrap gap-2">
                  {m.chips.map((chip, idx) => (
                    <button
                      key={idx}
                      onClick={() => handleSend(chip)}
                      className="text-xs bg-white text-indigo-600 border border-indigo-100 px-3 py-2 rounded-xl hover:bg-indigo-50 hover:shadow-sm transition-all font-medium"
                    >
                      {chip}
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Input / Footer Area */}
      <div className="bg-white border-t border-slate-100 shadow-[0_-4px_12px_rgba(0,0,0,0.02)]">
        {/* Conditional Summary Overlay for Step 9 Only */}
        {session.step === 9 && (
           <div className="px-6 py-4 bg-teal-50/50 border-b border-teal-100 flex items-center justify-between">
              <p className="text-[11px] text-teal-700 font-semibold">✨ 结构化流程已闭环，您可在此继续畅聊</p>
              <div className="flex gap-2">
                 <button onClick={() => onNavigate('coach')} className="text-[10px] bg-white border border-teal-100 px-2 py-1 rounded-lg text-teal-600 font-bold">查看话术</button>
                 <button onClick={() => onNavigate('action')} className="text-[10px] bg-teal-600 text-white px-2 py-1 rounded-lg font-bold">查看计划</button>
              </div>
           </div>
        )}

        <div className="p-4">
          <div className="relative">
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={session.step >= 9 ? "继续输入以深入探索..." : "在此输入您的回复..."}
              rows={1}
              className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-3 px-4 pr-12 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-indigo-200 transition-all resize-none placeholder:text-slate-400"
              style={{ color: '#0f172a' }}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSend(input);
                }
              }}
            />
            <button
              onClick={() => handleSend(input)}
              disabled={!input.trim()}
              className="absolute right-2 top-1.5 p-2.5 bg-slate-900 text-white rounded-xl disabled:opacity-20 hover:bg-slate-800 transition-colors shadow-sm"
            >
              <Send size={16} />
            </button>
          </div>
          <div className="mt-3 flex justify-between items-center px-1">
            <p className="text-[10px] text-slate-400 font-medium">
              {session.step >= 9 ? "当前处于持续陪伴模式" : "坦诚输入有助于更精准的梳理"}
            </p>
            {session.step >= 9 ? (
              <button onClick={onRestart} className="flex items-center gap-1 text-[10px] font-bold text-slate-400 hover:text-rose-500 transition-colors">
                <RotateCcw size={10} /> 重新开始
              </button>
            ) : (
              <button onClick={() => handleSend("我想不清楚，给我点提示")} className="text-[10px] font-bold text-indigo-600 hover:text-indigo-700">
                跳过此步
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default SessionPage;

import { GoogleGenAI, Type } from "@google/genai";
import { IPTFocus, Session } from '../types';

// 使用环境变量中的 API_KEY 初始化客户端
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const STEP_DATA = [
  { step: 1, name: '目标定义', goal: '明确我们今天要解决的核心关系问题。' },
  { step: 2, name: '事件澄清', goal: '还原最近一次让您感到不适的互动细节。' },
  { step: 3, name: '情绪定位', goal: '识别在那一刻，您最真实的情绪反应。' },
  { step: 4, name: '需求澄清', goal: '挖掘情绪背后的心理需求是什么。' },
  { step: 5, name: '角色与期待', goal: '分析您与对方在这个关系中的角色期待。' },
  { step: 6, name: '循环识别', goal: '观察这种互动是否在重复某种模式。' },
  { step: 7, name: '沟通彩排', goal: '尝试用新的表达方式来改写局面。' },
  { step: 8, name: '行动计划', goal: '确定未来24小时内的一个微小行动。' },
  { step: 9, name: '咨询总结', goal: '回顾本次梳理的重点与下一步行动。' },
  { step: 10, name: '持续支持', goal: '基于已梳理的逻辑，陪伴您进行深度探索。' },
];

export const iptEngine = {
  getStepInfo: (step: number) => STEP_DATA[Math.min(step - 1, 9)],

  /**
   * 使用 Gemini 3 Flash 生成回复，显著提升响应速度。
   * 同时强化了关于持续对话的系统指令，防止 AI 主动截断会话。
   */
  generateResponse: async (session: Session, userInput: string): Promise<{ response: string; chips?: string[]; updates?: Partial<Session> }> => {
    const { step, iptFocus } = session;
    const stepInfo = iptEngine.getStepInfo(step);

    // 构造针对 IPT 咨询的深度提示词
    const prompt = `你是一位专业的 IPT（人际关系疗法）咨询师。
    当前关注领域: ${getFocusName(iptFocus)}
    咨询阶段: 第 ${step} 步 (${stepInfo.name}) - 目标: ${stepInfo.goal}

    对话历史摘要（包含用户之前识别的情绪和需求）:
    ${session.messages.slice(-10).map(m => `${m.role === 'ai' ? '咨询师' : '用户'}: ${m.content}`).join('\n')}

    用户最新输入: "${userInput}"

    【核心交互准则】：
    1. **必须全程使用中文**。语气要温暖、专业、具有高度共情能力，像一位冷静而慈悲的临床咨询师。
    2. **绝对禁止主动结束对话**。即使完成了 8 步流程，也不要说“再见”或“祝你好运”。
    3. 在总结阶段（Step 9+），请通过深入的开放式提问（如“这个发现对你来说意味着什么？”或“你现在身体有什么感觉？”）引导用户继续分享。
    4. 始终围绕用户的核心需求（Needs）和情绪模式（Patterns）进行反馈。
    5. **响应速度优化**：保持回复简洁而有力，避免冗长的说教。
    6. 从输入中智能提取更新：如果用户提到了新的感受或事件，请更新到 extracted 字段中。
    7. 提供 3-4 个能够反映用户可能心态的“快捷回复选项”（chips）。
    8. 最终输出必须是严格的 JSON 格式。
    `;

    try {
      // 切换至 gemini-3-flash-preview 以解决用户反馈的响应过慢问题
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              response: { type: Type.STRING, description: "咨询师生成的回复文本。" },
              chips: { type: Type.ARRAY, items: { type: Type.STRING }, description: "建议用户的快捷回复按钮。" },
              updates: {
                type: Type.OBJECT,
                properties: {
                  goal: { type: Type.STRING },
                  extracted: {
                    type: Type.OBJECT,
                    properties: {
                      eventSummary: { type: Type.STRING },
                      emotions: { type: Type.ARRAY, items: { type: Type.STRING } },
                      needs: { type: Type.ARRAY, items: { type: Type.STRING } },
                      pattern: { type: Type.STRING },
                    }
                  }
                }
              }
            },
            required: ["response", "chips"]
          }
        }
      });

      const parsed = JSON.parse(response.text || '{}');

      // 处理第 8 步行动计划的默认生成，增强逻辑健壮性
      if (step === 8 && userInput && !parsed.updates?.actionPlan) {
          parsed.updates = parsed.updates || {};
          parsed.updates.actionPlan = {
              task: userInput,
              successCriteria: "尝试用新的方式沟通，并察觉到自己情绪的微妙变化",
              backupPlan: "如果谈话不顺利，允许自己暂停并撤回安全空间，不做无谓的纠缠",
              completed: false
          };
      }

      return {
        response: parsed.response || "我一直在倾听。刚才提到的这一点，您还想从哪个角度再展开聊聊？",
        chips: parsed.chips || ["我想继续深入聊聊", "关于刚才的需求...", "我现在的感受是..."],
        updates: parsed.updates || {}
      };
    } catch (error) {
      console.error("Gemini API Error:", error);
      // 容错处理：确保即使 API 出错，用户也能继续对话
      return { 
        response: "抱歉，我刚才正在深思如何更好地支持您。关于您刚才分享的，您觉得最让您触动的是哪一部分？", 
        chips: ["我当下的情绪", "我想改变的沟通方式", "我的核心需求"] 
      };
    }
  },

  generateScripts: (session: Session) => {
    const need = session.extracted.needs[0] || "我的核心需求";
    const emotion = session.extracted.emotions[0] || "感到挺困扰的";
    const event = session.extracted.eventSummary || "最近发生的摩擦";

    return {
      gentle: `“我想和你聊聊关于${event}。其实我当时感到${emotion}，因为我真的很看重${need}。我们能不能试着换种方式？”`,
      firm: `“关于${event}，我希望你能明白，${need}对我来说非常重要。我不能接受那种被忽视的感觉，希望你能尊重我的边界。”`,
      short: `“关于这件事，我现在的感受是${emotion}，我最需要的是${need}。”`
    };
  }
};

function getFocusName(focus: IPTFocus): string {
  const map = {
    [IPTFocus.DISPUTES]: '人际冲突',
    [IPTFocus.TRANSITION]: '角色转变',
    [IPTFocus.GRIEF]: '哀伤处理',
    [IPTFocus.DEFICITS]: '社交孤立',
    [IPTFocus.UNCERTAIN]: '关系困扰'
  };
  return map[focus];
}

